import{_ as e,c as a,o as t,U as s}from"./chunks/framework.rW1nVq3Q.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/basic/react/cache.md","filePath":"docs/basic/react/cache.md","lastUpdated":1704776788000}'),o={name:"docs/basic/react/cache.md"},c=s(`<h2 id="什么是缓存" tabindex="-1">什么是缓存 <a class="header-anchor" href="#什么是缓存" aria-label="Permalink to &quot;什么是缓存&quot;">​</a></h2><blockquote><p>对之前请求过的文件进行缓存，便于下次访问时重复使用，提高访问速度，降低服务器压力</p></blockquote><blockquote><p>http 缓存机制主要在 http 响应头中设定，响应头中相关字段为 <code> Expires</code> <code>Cache-Control </code> <code> Last-Modified</code> <code>Etag </code></p></blockquote><h2 id="浏览器是如何判定是否使用缓存" tabindex="-1">浏览器是如何判定是否使用缓存 <a class="header-anchor" href="#浏览器是如何判定是否使用缓存" aria-label="Permalink to &quot;浏览器是如何判定是否使用缓存&quot;">​</a></h2><blockquote><p>Referer: <a href="https://github.com/chenqf/frontEndBlog/issues/18" target="_blank" rel="noreferrer">https://github.com/chenqf/frontEndBlog/issues/18</a></p></blockquote><h2 id="缓存规则" tabindex="-1">缓存规则 <a class="header-anchor" href="#缓存规则" aria-label="Permalink to &quot;缓存规则&quot;">​</a></h2><details><summary><b>强缓存：</b></summary><p><code>Expires</code> 到期时间由服务端产生，可能会与客户端时间产生误差</p><p><code>Cache-Control</code> max-age=240 在 4 分钟内再次访问该资源就会命中强缓存</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>max-age=xx：</span></span>
<span class="line"><span>    每次都会像服务器校验资源新鲜度</span></span>
<span class="line"><span>    没过期返回 304 从缓存读取资源</span></span>
<span class="line"><span>    过期返回 200 和新资源</span></span>
<span class="line"><span>no-cache：每次都返回 200 和新资源</span></span>
<span class="line"><span>no-store：不被缓存</span></span></code></pre></div><table><tr><td bgcolor="#eee"> 不过 Expires 是 HTTP 1.0 的东西，现在默认浏览器均默认使用 HTTP 1.1，所以它的作用基本忽略。 </td></tr><tr><td bgcolor="#eee"> 另一个问题是，到期时间是由服务端生成的，但是客户端时间可能跟服务端时间有误差，这就会导致缓存命中的误差。 </td></tr><tr><td bgcolor="#eee"> 所以 HTTP 1.1 的版本，使用 Cache-Control 替代。 </td></tr></table></details><details><summary><b>协商缓存：</b></summary><p><code>Last-Modifed/If-Modified-Since</code> 和 <code>Etag/If-None-Match</code> 是分别成对出现的，呈一一对应关系</p></details>`,8),n=[c];function r(d,l,p,i,h,b){return t(),a("div",null,n)}const m=e(o,[["render",r]]);export{_ as __pageData,m as default};
